public int[] findFirstAndLast(int[] arr) {
    int[] result = new int[2];
    for (int i = 0; i < arr.length; i++) {
        if (arr[i] == 1) {
            result[0] = i;
        }
    }
    for (int i = 0; i < arr.length; i++) {
