public int[] findFirstAndLast(int[] arr) {
    int[] result = new int[2];
    for (int i = 0; i < arr.length; i++) {
        if (arr[i] == 1) {
            result[0] = i;
            break;
        }
    }
    for (int i = arr.length - 1; i >= 0; i--) {
        if (arr[i] == 1) {
            result[1] = i;
            break;
        }
    }
    return result;
}

