// buggy lines start
            if (stack.isEmpty()) {
                return false;
            }
// buggy lines end
            char popped = stack.pop();
            if (c == ')' && popped != '(' ||
                c == ']' && popped != '[' ||
                c == '}' && popped != '{') {
                return false;
            }
        }
    }
    return stack.isEmpty();
}

