    if (row == 0 || col == 0) return 0;
    else if (row == 1 && col == 1) return cost[row][col];
    else if (row == 1) return cost[row][col] + getMinCost(cost, row, col - 1);
    else if (col == 1) return cost[row][col] + getMinCost(cost, row - 1, col);
    else return cost[row][col] + Math.min(getMinCost(cost, row - 1, col), getMinCost(cost, row, col - 1));
}

