public boolean isValid(String s) {
    if (s.length() % 2 == 1) {
        return false;
    }
    Stack<Character> leftStack = new Stack<>();
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '(' || c == '[' || c == '{') {
            leftStack.push(c);
        } else {
            if (leftStack.isEmpty()) {
                return false;
            }
            if (c == ')' && leftStack.peek() != '(') {
                return false;
            }
            if (c == ']' && leftStack.peek() != '[') {
                return false;
            }
            if (c == '}' && leftStack.peek() != '{') {
                return false;
            }
            leftStack.pop();
        }
    }
    return leftStack.isEmpty();
} [/INST]

