public static int[] removeDuplicates(int[] arr) {
    int[] unique = new int[arr.length];
    int count = 0;
    for (int i = 0; i < arr.length; i++) {
        boolean found = false;
        for (int j = 0; j < i; j++) {
            if (arr[i] == arr[j]) {
                found = true;
                break;
            }
        }
        if (!found) {
            unique[count++] = arr[i];
        }
    }
    return Arrays.copyOf(unique, count);
}

