    int[] left;
    int[] right;
    int[] result = new int[arr.length];

    if (arr.length <= 1) {
        return arr;
    }

    int middle = arr.length / 2;

    left = Arrays.copyOfRange(arr, 0, middle);
    right = Arrays.copyOfRange(arr, middle, arr.length);

    left = mergeSort(left);
    right = mergeSort(right);

    result = merge(left, right);
    return result;
