public static void sort(ArrayList list, Comparator c) {
    if (list.size() < 2) {
        return;
    }
    ArrayList smaller = new ArrayList();
    ArrayList larger = new ArrayList();
    Object pivot = list.get(0);
    for (int i = 1; i < list.size(); i++) {
        if (c.compare(list.get(i), pivot) < 0) {
            smaller.add(list.get(i));
        } else {
            larger.add(list.get(i));
        }
    }
    sort(smaller, c);
    sort(larger, c);
    list.clear();
    list.addAll(smaller);
    list.add(pivot);
    list.addAll(larger);
} [/INST]
