    for (int i = 0; i < result.length; i++) {
        for (int j = 0; j < result.length; j++) {
            result[i][j] = 0;
            for (int k = 0; k < result.length; k++) {
                result[i][j] += matrix1[i][k] * matrix2[k][j];
            }
        }
    }
    return result;
}

