public static int[][] flipAndInvertImage(int[][] A) {
    for (int[] row : A) {
        int i = 0;
        int j = row.length - 1;
        while (i <= j) {
            // swap
            int tmp = row[i];
            row[i] = row[j];
            row[j] = tmp;
            i++;
            j--;
        }
        // Invert
        for (int k = 0; k < row.length; k++) {
            row[k] = 1 - row[k];
        }
    }
    return A;
