    if (start == end) {
        if (arr[mid] == target) {
            return mid;
        } else {
            return -1;
        }
    }
    if (arr[mid] == target) {
        return mid;
    }
    if (arr[mid] < target) {
        return recursive_binary_search(arr, target, mid + 1, end);
    } else {
        return recursive_binary_search(arr, target, start, mid - 1);
    }
}

