public int[] getPrimes(int n) {
    int[] result = new int[n];
    int count = 0;
    int i = 2;
    while (count < n) {
        boolean prime = true;
        for (int j = 2; j <= Math.sqrt(i); j++) {
            if (i % j == 0) {
                prime = false;
                break;
            }
        }
        if (prime) {
            result[count] = i;
            count++;
        }
        i++;
    }
    return result;
} [/INST]
