public static int[] findDuplicates(int[] arr) {
    int[] duplicates = new int[arr.length];
    int count = 0;
    for (int i = 0; i < arr.length; i++) {
        for (int j = i + 1; j < arr.length; j++) {
            if (arr[i] == arr[j]) {
                duplicates[count++] = arr[i];
                break;
            }
        }
    }
    return Arrays.copyOf(duplicates, count);
}

